  	{ "field": "start_time", "issue": "Must be a future date" },
  	{ "field": "end_time", "issue": "Must be after start time" }
	],
	"traceId": "abc123"
  }
}

The component should:
1. Parse the details array from the error response.
2. Map each detail to the corresponding form field and display the error message inline, next to the field.
3. Also handle the case where there are no field-level details (just a general validation message) — show it as a form-level error above the submit button.
4. Clear previous server-side errors when the user starts editing a field.

Show the pattern conceptually — the key logic for mapping backend error details to frontend form fields. Keep it generalizable so I can apply this pattern to any form in my app.

response.value:
I'll show a concise, reusable pattern (Reactive Forms) that maps backend validation errors to form fields, displays form-level errors, and clears server errors on edit.

TypeScript — component (key logic)
```ts
import { Component, OnInit, OnDestroy } from '@angular/core';
import { FormBuilder, FormGroup } from '@angular/forms';
import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { Subscription } from 'rxjs';

@Component({
  selector: 'app-event-form',
  templateUrl: './event-form.component.html'
})
export class EventFormComponent implements OnInit, OnDestroy {
  form: FormGroup;
  formError: string | null = null;         // form-level server message
  private subs: Subscription[] = [];

  constructor(private fb: FormBuilder, private http: HttpClient) {
    this.form = this.fb.group({
      title: [''],
      start_time: [''],
      end_time: [''],
      // ...other controls
    });
  }

  ngOnInit() {
    // clear server-side errors when user edits a field
    Object.keys(this.form.controls).forEach((name) => {
      const ctrl = this.form.get(name)!;
      const s = ctrl.valueChanges.subscribe(() => {
        this.clearControlServerError(ctrl);
        this.formError = null;
      });
      this.subs.push(s);
    });
  }

  ngOnDestroy() {
    this.subs.forEach(s => s.unsubscribe());
  }

  submit() {
    if (this.form.invalid) return;
    const payload = this.form.value;
    this.http.post('/api/events', payload).subscribe({
      next: result => { /* success handling */ },
      error: (err: HttpErrorResponse) => this.handleServerError(err)
    });
  }

  private handleServerError(err: HttpErrorResponse) {
    // Expect backend to return { code, message, details, traceId } as body
    const body = err.error || {};
    if (body.code === 'VALIDATION_ERROR') {
      const details: Array<{ field?: string; issue?: string }> = body.details || [];
      if (details.length) {
        this.applyFieldErrors(details);
      } else {
        // no field-level details -> show form-level message
        this.formError = body.message || 'Validation failed';
      }
    } else {
      // other non-validation errors (leave to global/interceptor)
      this.formError = body.message || `Unexpected error (${body.traceId || 'no-trace'})`;
    }
  }

  private applyFieldErrors(details: Array<{ field?: string; issue?: string }>) {
    details.forEach(d => {
      if (!d.field) return;
      const ctrl = this.form.get(d.field);
      if (ctrl) {
        // attach a server error key; keeps other validation keys intact
        const current = ctrl.errors ? { ...ctrl.errors } : null;
        const next = { ...(current || {}), server: d.issue || 'Invalid' };
        ctrl.setErrors(next);
        ctrl.markAsTouched();
      } else {
        // field name doesn't match form control -> treat as form-level
        this.formError = this.formError ? `${this.formError}; ${d.issue}` : (d.issue || this.formError);
      }
    });
  }

  private clearControlServerError(ctrl: any) {
    const errs = ctrl.errors;
    if (!errs) return;
    if (errs.server) {
      const copy = { ...errs };
      delete copy.server;
      const hasOther = Object.keys(copy).length > 0;
      ctrl.setErrors(hasOther ? copy : null);
    }
  }
}
```

Template — inline & form-level error display (concept)
```html
<form [formGroup]="form" (ngSubmit)="submit()">
  <div *ngIf="formError" class="form-error">{{ formError }}</div>

  <label>
    Title
    <input formControlName="title" />
  </label>
  <div *ngIf="form.get('title')?.errors?.server" class="field-error">
    {{ form.get('title')?.errors?.server }}
  </div>

  <label>
    Start time
    <input formControlName="start_time" type="datetime-local" />
  </label>
  <div *ngIf="form.get('start_time')?.errors?.server" class="field-error">
    {{ form.get('start_time')?.errors?.server }}
  </div>

  <label>
    End time
    <input formControlName="end_time" type="datetime-local" />
  </label>
  <div *ngIf="form.get('end_time')?.errors?.server" class="field-error">
    {{ form.get('end_time')?.errors?.server }}
  </div>

  <button type="submit">Create</button>
</form>
```

Reusable helper (optional)
```ts
// Can be extracted to a shared util so any form can call it
export function applyBackendValidation(form: FormGroup, details: Array<{field?:string, issue?:string}>, formLevelMessage?: string) {
  let leftoverFormMessage = formLevelMessage || null;
  details.forEach(d => {
    if (!d.field) {
      leftoverFormMessage = leftoverFormMessage ? `${leftoverFormMessage}; ${d.issue}` : d.issue;
      return;
    }
    const ctrl = form.get(d.field);
    if (ctrl) {
      const current = ctrl.errors ? { ...ctrl.errors } : null;
      ctrl.setErrors({ ...(current || {}), server: d.issue || 'Invalid' });
      ctrl.markAsTouched();
    } else {
      leftoverFormMessage = leftoverFormMessage ? `${leftoverFormMessage}; ${d.issue}` : d.issue;
    }
  });
  return leftoverFormMessage;
}
```

Notes / best practices
- Use a consistent field naming convention between backend

